   185	    LOG_E(GTPU,"try to get a gtp-u not existing output\n");     \
   186	    pthread_mutex_unlock(&globGtp.gtp_lock);                    \
   187	    return GTPNOK;                                                     \
   188	  }                                                             \
   189	  gtpEndPoint * inst=&instChk->second;
   190	
   191	
   192	#define getUeRetVoid(insT, Ue)                                            \
   193	    auto ptrUe=insT->ue2te_mapping.find(Ue);                        \
   194	                                                                        \
   195	  if (  ptrUe==insT->ue2te_mapping.end() ) {                          \
   196	    LOG_E(GTPU, "[%ld] gtpv1uSend failed: while getting ue id %ld in hashtable ue_mapping\n", instance, ue_id); \
   197	    pthread_mutex_unlock(&globGtp.gtp_lock);                            \
   198	    return;                                                             \
